export function getInstitutionBySlug(slug: string): Institution | undefined {
  return institutions.find((i) => i.slug === slug);
}

export function getProvinceFromHeadOffice(headOffice: string): string {
  const provinceMap: [string, string][] = [
    ["Kathmandu", "Bagmati"], ["Lalitpur", "Bagmati"], ["Bhaktapur", "Bagmati"],
    ["Kavrepalanchowk", "Bagmati"], ["Dhading", "Bagmati"], ["Nuwakot", "Bagmati"],
    ["Chitwan", "Bagmati"], ["Dhulikhel", "Bagmati"],
    ["Pokhara", "Gandaki"], ["Kaski", "Gandaki"], ["Tanahu", "Gandaki"], ["Lamjung", "Gandaki"], ["Nawalparasi", "Gandaki"],
    ["Butwal", "Lumbini"], ["Rupandehi", "Lumbini"], ["Dang", "Lumbini"], ["Kapilvastu", "Lumbini"],
    ["Morang", "Koshi"], ["Sunsari", "Koshi"], ["Jhapa", "Koshi"], ["Dhankuta", "Koshi"],
    ["Dhanusha", "Madhesh"], ["Saptari", "Madhesh"], ["Mahottari", "Madhesh"], ["Siraha", "Madhesh"],
    ["Kailali", "Sudurpashchim"], ["Salyan", "Karnali"],
  ];
  for (const [keyword, province] of provinceMap) {
    if (headOffice.toLowerCase().includes(keyword.toLowerCase())) return province;
  }
  return "Bagmati";
}
